using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class TicketPurchaseService
{
    private readonly BookingDbContext _context;

    public TicketPurchaseService(BookingDbContext context)
    {
        _context = context;
    }

    public async Task<PurchaseResult> PurchaseTicketsAsync(int eventId, int userId, int quantity)
    {
        if (quantity <= 0)
        {
            return new PurchaseResult 
            { 
                Success = false, 
                ErrorMessage = "Quantity must be greater than zero" 
            };
        }

        using var transaction = await _context.Database.BeginTransactionAsync(
            System.Data.IsolationLevel.Serializable);

        try
        {
            var eventEntity = await _context.Events
                .Where(e => e.Id == eventId)
                .FirstOrDefaultAsync();

            if (eventEntity == null)
            {
                return new PurchaseResult 
                { 
                    Success = false, 
                    ErrorMessage = "Event not found" 
                };
            }

            if (eventEntity.AvailableSeats < quantity)
            {
                return new PurchaseResult 
                { 
                    Success = false, 
                    ErrorMessage = $"Insufficient seats. Available: {eventEntity.AvailableSeats}, Requested: {quantity}" 
                };
            }

            var rowsAffected = await _context.Database.ExecuteSqlInterpolatedAsync(
                $@"UPDATE Events 
                   SET AvailableSeats = AvailableSeats - {quantity}
                   WHERE Id = {eventId} AND AvailableSeats >= {quantity}");

            if (rowsAffected == 0)
            {
                return new PurchaseResult 
                { 
                    Success = false, 
                    ErrorMessage = "Seats no longer available due to concurrent purchase" 
                };
            }

            var purchase = new Purchase
            {
                EventId = eventId,
                UserId = userId,
                Quantity = quantity,
                PurchaseDate = DateTime.UtcNow,
                TotalPrice = eventEntity.PricePerTicket * quantity
            };

            _context.Purchases.Add(purchase);
            await _context.SaveChangesAsync();

            await transaction.CommitAsync();

            return new PurchaseResult 
            { 
                Success = true, 
                PurchaseId = purchase.Id,
                TotalPrice = purchase.TotalPrice
            };
        }
        catch (Exception ex)
        {
            await transaction.RollbackAsync();
            return new PurchaseResult 
            { 
                Success = false, 
                ErrorMessage = $"Purchase failed: {ex.Message}" 
            };
        }
    }

    public async Task<PurchaseResult> PurchaseTicketsWithOptimisticLockAsync(int eventId, int userId, int quantity)
    {
        if (quantity <= 0)
        {
            return new PurchaseResult 
            { 
                Success = false, 
                ErrorMessage = "Quantity must be greater than zero" 
            };
        }

        const int maxRetries = 3;
        int retryCount = 0;

        while (retryCount < maxRetries)
        {
            using var transaction = await _context.Database.BeginTransactionAsync();

            try
            {
                var eventEntity = await _context.Events
                    .Where(e => e.Id == eventId)
                    .FirstOrDefaultAsync();

                if (eventEntity == null)
                {
                    return new PurchaseResult 
                    { 
                        Success = false, 
                        ErrorMessage = "Event not found" 
                    };
                }

                if (eventEntity.AvailableSeats < quantity)
                {
                    return new PurchaseResult 
                    { 
                        Success = false, 
                        ErrorMessage = $"Insufficient seats. Available: {eventEntity.AvailableSeats}, Requested: {quantity}" 
                    };
                }

                eventEntity.AvailableSeats -= quantity;

                var purchase = new Purchase
                {
                    EventId = eventId,
                    UserId = userId,
                    Quantity = quantity,
                    PurchaseDate = DateTime.UtcNow,
                    TotalPrice = eventEntity.PricePerTicket * quantity
                };

                _context.Purchases.Add(purchase);
                await _context.SaveChangesAsync();

                await transaction.CommitAsync();

                return new PurchaseResult 
                { 
                    Success = true, 
                    PurchaseId = purchase.Id,
                    TotalPrice = purchase.TotalPrice
                };
            }
            catch (DbUpdateConcurrencyException)
            {
                await transaction.RollbackAsync();
                retryCount++;

                if (retryCount >= maxRetries)
                {
                    return new PurchaseResult 
                    { 
                        Success = false, 
                        ErrorMessage = "Purchase failed due to high concurrency. Please try again." 
                    };
                }

                await Task.Delay(100 * retryCount);
            }
            catch (Exception ex)
            {
                await transaction.RollbackAsync();
                return new PurchaseResult 
                { 
                    Success = false, 
                    ErrorMessage = $"Purchase failed: {ex.Message}" 
                };
            }
        }

        return new PurchaseResult 
        { 
            Success = false, 
            ErrorMessage = "Purchase failed after maximum retries" 
        };
    }
}

public class BookingDbContext : DbContext
{
    public DbSet<Event> Events { get; set; }
    public DbSet<Purchase> Purchases { get; set; }

    public BookingDbContext(DbContextOptions<BookingDbContext> options) : base(options)
    {
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Event>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.RowVersion).IsRowVersion();
            entity.Property(e => e.AvailableSeats).IsConcurrencyToken();
        });

        modelBuilder.Entity<Purchase>(entity =>
        {
            entity.HasKey(p => p.Id);
            entity.HasOne<Event>()
                .WithMany()
                .HasForeignKey(p => p.EventId);
        });
    }
}

